SELECT e.id, d::date,
  CASE WHEN EXTRACT(DOW FROM d) IN (0,6) THEN NULL
       WHEN e.id='22222222-0000-0000-0000-000000000004' AND d::date BETWEEN '2026-03-03' AND '2026-03-05' THEN NULL
       WHEN e.id='22222222-0000-0000-0000-000000000009' AND d::date BETWEEN '2026-03-10' AND '2026-03-12' THEN NULL
       WHEN e.id='22222222-0000-0000-0000-000000000001' THEN d+INTERVAL '8 hours'+(floor(random()*10)::int*INTERVAL '1 minute')
       WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN d+INTERVAL '10 hours'+(floor(random()*30)::int*INTERVAL '1 minute')
       WHEN e.id IN ('22222222-0000-0000-0000-000000000005','22222222-0000-0000-0000-000000000007') THEN d+INTERVAL '9 hours'+(floor(random()*45)::int*INTERVAL '1 minute')
       ELSE d+INTERVAL '9 hours'+(floor(random()*20)::int*INTERVAL '1 minute') END,
  CASE WHEN EXTRACT(DOW FROM d) IN (0,6) THEN NULL
       WHEN e.id='22222222-0000-0000-0000-000000000004' AND d::date BETWEEN '2026-03-03' AND '2026-03-05' THEN NULL
       WHEN e.id='22222222-0000-0000-0000-000000000009' AND d::date BETWEEN '2026-03-10' AND '2026-03-12' THEN NULL
       WHEN e.id='22222222-0000-0000-0000-000000000001' THEN d+INTERVAL '20 hours'+(floor(random()*30)::int*INTERVAL '1 minute')
       WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN d+INTERVAL '16 hours'+(floor(random()*30)::int*INTERVAL '1 minute')
       ELSE d+INTERVAL '18 hours'+(floor(random()*60)::int*INTERVAL '1 minute') END,
  CASE WHEN EXTRACT(DOW FROM d) IN (0,6) THEN 0
       WHEN e.id='22222222-0000-0000-0000-000000000001' THEN 11+round((random()*1)::numeric,1)
       WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN 6+round((random()*1)::numeric,1)
       WHEN e.id IN ('22222222-0000-0000-0000-000000000005','22222222-0000-0000-0000-000000000007') THEN 7.5+round((random()*1)::numeric,1)
       ELSE 8.5+round((random()*1.5)::numeric,1) END,
  CASE WHEN EXTRACT(DOW FROM d) IN (0,6) THEN 0
       WHEN e.id='22222222-0000-0000-0000-000000000001' THEN round((1+random()*2)::numeric,1)
       WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN 0
       ELSE round((random()*0.8)::numeric,1) END,
  CASE WHEN EXTRACT(DOW FROM d) IN (0,6) THEN 'weekend'
       WHEN e.id='22222222-0000-0000-0000-000000000004' AND d::date BETWEEN '2026-03-03' AND '2026-03-05' THEN 'on_leave'
       WHEN e.id='22222222-0000-0000-0000-000000000009' AND d::date BETWEEN '2026-03-10' AND '2026-03-12' THEN 'on_leave'
       WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') AND random()<0.1 THEN 'absent'
       WHEN e.id IN ('22222222-0000-0000-0000-000000000005','22222222-0000-0000-0000-000000000007') AND random()<0.06 THEN 'absent'
       WHEN e.id='22222222-0000-0000-0000-000000000006' AND EXTRACT(DOW FROM d)=3 THEN 'work_from_home'
       WHEN e.id='22222222-0000-0000-0000-000000000008' AND EXTRACT(DOW FROM d)=1 THEN 'work_from_home'
       WHEN random()<0.03 THEN 'absent'
       ELSE 'present' END,
  CASE WHEN e.id IN ('22222222-0000-0000-0000-000000000006','22222222-0000-0000-0000-000000000008') THEN 'work_from_home' ELSE 'office' END
FROM employees e,
     generate_series(CURRENT_DATE-INTERVAL '90 days', CURRENT_DATE, '1 day') AS d
ON CONFLICT (employee_id,date) DO NOTHING;


SELECT r.id, e.id, r.pay_period, 26,
  CASE WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN 20
       WHEN e.id IN ('22222222-0000-0000-0000-000000000005','22222222-0000-0000-0000-000000000007') THEN 22 ELSE 24 END,
  CASE WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN 3
       WHEN e.id IN ('22222222-0000-0000-0000-000000000005','22222222-0000-0000-0000-000000000007') THEN 2 ELSE 0 END,
  CASE WHEN e.id IN ('22222222-0000-0000-0000-000000000004','22222222-0000-0000-0000-000000000009') THEN 3 ELSE 2 END,
  s.base_salary, s.hra, s.transport_allowance, s.medical_allowance, s.special_allowance,
  CASE WHEN r.pay_period IN ('2025-12','2026-03') AND e.id='22222222-0000-0000-0000-000000000001' THEN 50000
       WHEN r.pay_period IN ('2025-12','2026-03') THEN ROUND(s.base_salary*0.10) ELSE 0 END,
  CASE WHEN e.id='22222222-0000-0000-0000-000000000001' THEN 8000 ELSE ROUND(random()*1500) END,
  s.base_salary+s.hra+s.transport_allowance+s.medical_allowance+s.special_allowance+
    CASE WHEN r.pay_period IN ('2025-12','2026-03') THEN ROUND(s.base_salary*0.10) ELSE 0 END,
  s.pf_employee, s.esi_employee, s.professional_tax, s.income_tax_tds,
  s.pf_employee+s.esi_employee+s.professional_tax+s.income_tax_tds,
  (s.base_salary+s.hra+s.transport_allowance+s.medical_allowance+s.special_allowance+
    CASE WHEN r.pay_period IN ('2025-12','2026-03') THEN ROUND(s.base_salary*0.10) ELSE 0 END)
  -(s.pf_employee+s.esi_employee+s.professional_tax+s.income_tax_tds),
  'paid', (r.run_date+INTERVAL '2 days')::date
FROM payroll_runs r
CROSS JOIN employees e
JOIN salary_structures s ON s.employee_id=e.id AND s.is_current=TRUE
ON CONFLICT DO NOTHING;


SELECT 'employees' AS tbl,COUNT(*) FROM employees
UNION ALL SELECT 'leave_requests',COUNT(*) FROM leave_requests
UNION ALL SELECT 'payslips',COUNT(*) FROM payslips
UNION ALL SELECT 'attendance',COUNT(*) FROM attendance
UNION ALL SELECT 'bonuses',COUNT(*) FROM bonuses;
